import subprocess
from tqdm import tqdm

def install_with_pip():
    """Install required python modules using pip."""
    
    # Using requirements file to get all necessary packages 
    with open("requirements.txt", 'r') as f:        
        package_names = [line for line in f.read().splitlines() if not line.startswith('#') and len(line) > 0]      
    
    # Use pip install -U to upgrade packages but don't hash verification 
    subprocess.call(['pip', 'install'] + package_names, stdout=subprocess.DEVNULL, stderr=subprocess.STDOUT)  
        
def main():      
     print("Installing required python modules using pip...")       
     
if __name__ == "__main__":   
     install_with_pip()  # Install the packages specified in requirements file from command line